  ('colonel-7fec267e-moex-00259', 'colonel-7fec267e', 'colonel-7fec267e-moex-110-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於行政處分之效力，下列敘述何者正確？', '["納稅義務人於法定救濟期間經過後不得對課稅處分提起行政爭訟，係因 課稅處分發生實質存續力", "公司違法，主管機關依法針對公司登記之負責人裁罰，係因公司登記之 處分對其發生構成要件效力", "勞工機關裁罰違法僱用外籍移工之公司，內政部移民署得基於該處分之 執行力而限期令該外籍移工出國", "社福機關對違法長期照護中心裁罰後拒不繳納，因該裁罰處分已具確認 效力，得直接移送行政執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:59+00:00", "source_pdf_sha1": "2f314779229e", "answer_pdf_sha1": "2390de2c8cd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00260', 'colonel-7fec267e', 'colonel-7fec267e-moex-110-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '依行政程序法之規定，關於和解契約之敘述，下列何者正確？', '["僅限於法律關係之部分，始得和解", "須雙方讓步始得成立和解契約", "無須經職權調查，即可成立和解契約", "須得上級機關之核准"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:59+00:00", "source_pdf_sha1": "2f314779229e", "answer_pdf_sha1": "2390de2c8cd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00261', 'colonel-7fec267e', 'colonel-7fec267e-moex-110-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '某直轄市衛生局發布登革熱疫情警報，提醒市民移除家中廢棄物，對此發 布下列敘述何者錯誤？', '["此發布為行政事實行為", "此發布行為無法律保留原則之適用", "行政機關得依此發布強制市民清除廢棄物", "人民對此發布不服時，不得提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:59+00:00", "source_pdf_sha1": "2f314779229e", "answer_pdf_sha1": "2390de2c8cd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
